import httpx
import json
from pathlib import Path
from typing import Dict, List, Optional, AsyncGenerator, Any
from rich.console import Console

console = Console()
from .config import ModelConfig

class LMStudioClient:
    """Client for interacting with LM Studio's OpenAI-compatible API"""

    def __init__(self, model_config: ModelConfig):
        self.config = model_config
        self.base_url = "http://localhost:1234/v1"
        self.client = None
        self.current_model = None
        self.interactive_mode = False
        self.history = None

    async def __aenter__(self):
        """Async context manager entry"""
        timeout = httpx.Timeout(None)  # No timeout for slow model loading
        self.client = httpx.AsyncClient(timeout=timeout)
        return self

    async def __aexit__(self, exc_type, exc_val, exc_tb):
        """Async context manager exit"""
        if self.client:
            await self.client.aclose()

    def update_config(self, model_config: ModelConfig):
        """Update the model configuration"""
        self.config = model_config

    async def is_available(self) -> bool:
        """Check if LM Studio server is available"""
        try:
            if not self.client:
                timeout = httpx.Timeout(5.0)
                async with httpx.AsyncClient(timeout=timeout) as client:
                    response = await client.get(f"{self.base_url}/models")
                    return response.status_code == 200
            else:
                response = await self.client.get(f"{self.base_url}/models", timeout=5.0)
                return response.status_code == 200
        except:
            return False

    async def is_model_available(self) -> bool:
        """Check if the configured model is available in LM Studio"""
        try:
            if not self.client:
                timeout = httpx.Timeout(5.0)
                async with httpx.AsyncClient(timeout=timeout) as client:
                    response = await client.get(f"{self.base_url}/models")
            else:
                response = await self.client.get(f"{self.base_url}/models", timeout=5.0)

            if response.status_code == 200:
                data = response.json()
                models = [m.get("id", "") for m in data.get("data", [])]
                # Check if our model name matches any loaded model
                return any(self.config.name.lower() in m.lower() for m in models)
            return False
        except:
            return False

    async def list_models(self) -> List[str]:
        """List all available models in LM Studio"""
        try:
            if not self.client:
                timeout = httpx.Timeout(5.0)
                async with httpx.AsyncClient(timeout=timeout) as client:
                    response = await client.get(f"{self.base_url}/models")
            else:
                response = await self.client.get(f"{self.base_url}/models", timeout=5.0)

            if response.status_code == 200:
                data = response.json()
                return [m.get("id", "unknown") for m in data.get("data", [])]
            return []
        except:
            return []

    async def stream_generate(
        self,
        prompt: str,
        system_prompt: Optional[str] = None,
        task_type: Optional[str] = None,
        num_predict_override: Optional[int] = None,
        temperature_override: Optional[float] = None,
        options_override: Optional[Dict[str, Any]] = None,
        options: Optional[Dict[str, Any]] = None,
        tools: Optional[List[Dict]] = None
    ) -> AsyncGenerator[str, None]:
        """Generate response using LM Studio with streaming output"""

        if not self.client:
            raise Exception("LMStudioClient must be used as async context manager")

        # Build messages array
        messages = []
        if system_prompt:
            messages.append({"role": "system", "content": system_prompt})
        messages.append({"role": "user", "content": prompt})

        # Apply overrides
        max_tokens = num_predict_override if num_predict_override else (self.config.max_tokens if hasattr(self.config, 'max_tokens') else 2048)
        temperature = temperature_override if temperature_override is not None else (self.config.temperature if hasattr(self.config, 'temperature') else 0.7)

        # Build request payload
        payload = {
            "model": self.config.name,
            "messages": messages,
            "max_tokens": max_tokens,
            "temperature": temperature,
            "stream": True
        }

        # Add tools if provided
        if tools:
            payload["tools"] = tools
            payload["tool_choice"] = "auto"

        console.print(f"[dim cyan]▶ Starting LM Studio generation...[/dim cyan]")

        if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
            console.print(f"[dim cyan]DEBUG: LM Studio request: {json.dumps(payload, indent=2)[:200]}...[/dim cyan]")

        try:
            # Stream response
            async with self.client.stream('POST', f"{self.base_url}/chat/completions", json=payload) as response:
                if response.status_code != 200:
                    error_text = await response.aread()
                    raise Exception(f"LM Studio API error: {response.status_code} - {error_text.decode()}")

                console.print(f"[dim green]✓ LM Studio streaming...[/dim green]")

                async for line in response.aiter_lines():
                    if not line or line == "data: [DONE]":
                        continue

                    if line.startswith("data: "):
                        line = line[6:]  # Remove "data: " prefix

                    try:
                        chunk_data = json.loads(line)
                        choices = chunk_data.get("choices", [])
                        if choices:
                            delta = choices[0].get("delta", {})

                            # Handle content chunks
                            if "content" in delta and delta["content"]:
                                yield delta["content"]

                            # Handle tool calls
                            if "tool_calls" in delta:
                                # For now, just yield the tool call as JSON
                                # TODO: Proper tool call handling
                                tool_call = delta["tool_calls"][0]
                                yield f"\n[TOOL_CALL: {json.dumps(tool_call)}]\n"
                    except json.JSONDecodeError:
                        continue

        except Exception as e:
            console.print(f"[red]Error during LM Studio generation: {e}[/red]")
            raise

    async def generate(
        self,
        prompt: str,
        system_prompt: Optional[str] = None,
        task_type: Optional[str] = None,
        num_predict_override: Optional[int] = None,
        temperature_override: Optional[float] = None,
        options_override: Optional[Dict[str, Any]] = None,
        options: Optional[Dict[str, Any]] = None,
        tools: Optional[List[Dict]] = None
    ) -> str:
        """Non-streaming generation (collect all output)"""
        result = ""
        async for chunk in self.stream_generate(
            prompt, system_prompt, task_type,
            num_predict_override, temperature_override, options_override,
            options, tools
        ):
            result += chunk
        return result.strip()

    async def unload_model(self) -> bool:
        """Unload model (no-op for LM Studio - managed via GUI)"""
        return True
